* TIM1 -- shared input form for TIMR (REXX) and TIMC (COBOL). The
* operator types a delay in seconds and a reminder message; the
* program then EXEC CICS START's itself with INTERVAL(...) and the
* message in FROM(...), so the same transaction fires again after
* the delay and renders the reminder via the TIM2 map.
MAP TIM1 SIZE 24x80
  FIELD AT 0,2  LEN 30 PROT BRIGHT COLOR=BLUE  "Timed Reminder -- schedule"
  FIELD AT 0,60 LEN 5  PROT COLOR=BLUE         "TERM="
  INPUT TERMID  AT 0,65 LEN 8  PROT COLOR=BLUE
  FIELD AT 4,4  LEN 60 PROT COLOR=BLUE         "Schedule a reminder via EXEC CICS START."
  FIELD AT 6,4  LEN 14 PROT                    "Seconds:"
  INPUT SECS    AT 6,19 LEN 4  UNDERSCORE COLOR=GREEN NUMERIC
  STOP          AT 6,24
  FIELD AT 8,4  LEN 14 PROT                    "Message:"
  INPUT MSG     AT 8,19 LEN 50 UNDERSCORE COLOR=GREEN
  STOP          AT 8,70
  INPUT INFO    AT 18,4 LEN 70 PROT BRIGHT COLOR=RED
  FIELD AT 22,2 LEN 50 PROT COLOR=BLUE         "ENTER=Schedule  PF3=Cancel"
  CURSOR        AT 6,20
ENDMAP
